if (!body?.message?.chatid || !body?.message?.messageTimestamp) {
  throw new Error(`Payload Uazapi inválido: ${JSON.stringify(body || {}).slice(0, 200)}`);
}
return $input.all();

const TZ = 'America/Sao_Paulo';
const pad = (n) => String(n).padStart(2, '0');
const nomes = ['domingo', 'segunda-feira', 'terça-feira', 'quarta-feira', 'quinta-feira', 'sexta-feira', 'sábado'];

function nowInTimeZone(timeZone) {
  const dtf = new Intl.DateTimeFormat('en-CA', {
    timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false,
  });

  const parts = dtf.formatToParts(new Date());
  const map = {};
  for (const p of parts) {
    if (p.type !== 'literal') map[p.type] = p.value;
  }

  return new Date(`${map.year}-${map.month}-${map.day}T${map.hour}:${map.minute}:${map.second}`);
}

const now = nowInTimeZone(TZ);

let result = `Hoje é ${nomes[now.getDay()]}, ${pad(now.getDate())}/${pad(now.getMonth() + 1)}/${now.getFullYear()} às ${pad(now.getHours())}:${pad(now.getMinutes())}\n`;

for (let i = 1; i <= 7; i++) {
  const future = new Date(now);
  future.setDate(now.getDate() + i);

  const dia = pad(future.getDate());
  const mes = pad(future.getMonth() + 1);
  const ano = future.getFullYear();
  const nomeDia = nomes[future.getDay()];

  if (i === 1) {
    result += `Amanhã é ${nomeDia}, ${dia}/${mes}/${ano}\n`;
  } else if (i === 2) {
    result += `Depois de amanhã é ${nomeDia}, ${dia}/${mes}/${ano}\n`;
  } else {
    result += `${nomeDia}, ${dia}/${mes}/${ano}\n`;
  }
}

return [{ json: { resultado: result.trim() } }];

